const file = $input.first().json;
const name = file.name || '';
const mime = file.mimeType || '';
const isVideo = mime.startsWith('video/') || /\.(mp4|mov|webm|mkv)$/i.test(name);
const isText = /\.(txt|md|srt)$/i.test(name);
if (!isVideo && !isText) throw new Error('Unsupported: ' + name);
const parents = (file.parents || []).map(p => (p.name || '').toLowerCase());
const folderPath = parents.join('/').toLowerCase();
let contentType = 'technical-walkthrough';
if (folderPath.includes('case-study') || folderPath.includes('casestudy')) contentType = 'case-study';
else if (folderPath.includes('podcast')) contentType = 'podcast';
const baseName = name.replace(/\.[^.]+$/, '');
const parts = baseName.split('_').map(p => p.trim());
let speakerName = '', company = '', title = baseName;
if (parts.length >= 3) { speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2'); company = parts[1].replace(/([a-z])([A-Z])/g, '$1 $2'); title = parts.slice(2).join(' '); }
else if (parts.length === 2) { speakerName = parts[0].replace(/([a-z])([A-Z])/g, '$1 $2'); title = parts[1]; }
return [{ json: { fileId: file.id, fileName: name, isVideo, isText, contentType, speakerName, company, title, mimeType: mime } }];

const w = $input.first().json;
const meta = $('Detect File Type + Content Type').first().json;
let transcript = '';
if (w.segments?.length) { transcript = w.segments.map(s => { const m = Math.floor(s.start / 60), sec = Math.floor(s.start % 60); return `[${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}] ${s.text.trim()}`; }).join('\n'); }
else transcript = w.text || '';
return [{ json: { body: { contentType: meta.contentType, transcript, videoUrl: '', speakerName: meta.speakerName, company: meta.company, metrics: [], title: meta.title }, fileId: meta.fileId, fileName: meta.fileName } }];

const item = $input.first();
const meta = $('Detect File Type + Content Type').first().json;
let transcript = '';
if (item.binary?.data) transcript = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
else if (item.json?.data) transcript = item.json.data;
if (!transcript || transcript.trim().length < 20) throw new Error('Transcript too short');
return [{ json: { body: { contentType: meta.contentType, transcript, videoUrl: '', speakerName: meta.speakerName, company: meta.company, metrics: [], title: meta.title }, fileId: meta.fileId, fileName: meta.fileName } }];

const input = $input.first().json;
const body = input.body;
const contentType = body.contentType || 'technical-walkthrough';
const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};
const systemPrompt = `B-roll scene generator for CUTAWAY format. Output JSON: { "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...}, "backgroundVideo": { "query": "..." } (optional) }], "textStrip": { "labels": [...] }, "lowerThirds": [...] }

Flow: ${FLOWS[contentType]}

ASSET HINTS (n8n auto-fills URLs):
- workflow-pipeline & node-graph nodes: set icon: "mdi:database" (Iconify name) — adds inline SVG
- logo-endorsement logos: set name only — Brandfetch fills imageUrl
- backgroundVideo: { query: "data center" } — Pexels/Pixabay/Mixkit fills url

FIRST-PASS DIAGNOSTIC: durationInFrames must be 180-360 frames (6-12s). Adjacent scenes overlap by 16+ frames. Percentages>95 need tickRange. No empty comparison-split sides. Realistic numbers (not inflated).

Types: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color,tickRange?}]}), workflow-pipeline({header,rows[[{label,sub?,glow?,icon?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color,icon?}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name,imageUrl?}]}), cta-comment({action,keyword})

frame=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Output ONLY JSON.`;
const context = [body.speakerName ? `Speaker: ${body.speakerName}` : '', body.company ? `Company: ${body.company}` : ''].filter(Boolean).join('
');
const userMessage = `${context ? context + '

' : ''}Transcript:
${body.transcript}`;
return [{ json: { ...input, systemPrompt, userMessage, contentType, title: body.title } }];

const prev = $('Build Claude Prompt').first().json;
const response = $input.first().json;
const content = response.content?.[0]?.text || '';
let config;
try { config = JSON.parse(content); }
catch (e) { const m = content.match(/\{[\s\S]*\}/); if (m) config = JSON.parse(m[0]); else throw new Error('parse fail'); }
const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);
return [{ json: { config, totalFrames, totalSeconds: (totalFrames / 30).toFixed(1), sceneCount: config.scenes.length, sceneTypes: config.scenes.map(s => s.type), title: prev.title, contentType: prev.contentType, sourceFileId: prev.fileId, sourceFileName: prev.fileName, generatedAt: new Date().toISOString() } }];

const item = $input.first().json;
const config = item.config;
const BRANDFETCH_KEY = $vars.BRANDFETCH_API_KEY;

for (const scene of config.scenes) {
  if (scene.type !== 'logo-endorsement') continue;
  for (const logo of scene.data.logos) {
    if (logo.imageUrl) continue;
    if (!logo.name) continue;
    try {
      const r = await fetch(`https://api.brandfetch.io/v2/brands/${encodeURIComponent(logo.name)}`, {
        headers: { 'Authorization': `Bearer ${BRANDFETCH_KEY}` }
      });
      if (!r.ok) continue;
      const data = await r.json();
      const icon = data.logos?.find(l => l.type === 'icon') || data.logos?.[0];
      const fmt = icon?.formats?.find(f => f.format === 'svg') || icon?.formats?.find(f => f.format === 'png') || icon?.formats?.[0];
      if (fmt?.src) logo.imageUrl = fmt.src;
    } catch (e) { /* skip on failure, text fallback renders */ }
  }
}
return [{ json: { ...item, config } }];

const item = $input.first().json;
const config = item.config;
const PEXELS_KEY = $vars.PEXELS_API_KEY;
const PIXABAY_KEY = $vars.PIXABAY_API_KEY;

async function pexels(query) {
  if (!PEXELS_KEY) return null;
  try {
    const r = await fetch(`https://api.pexels.com/videos/search?query=${encodeURIComponent(query)}&per_page=3&orientation=landscape`, { headers: { 'Authorization': PEXELS_KEY } });
    if (!r.ok) return null;
    const d = await r.json();
    const v = d.videos?.[0];
    const file = v?.video_files?.find(f => f.quality === 'hd' && f.width >= 1280) || v?.video_files?.[0];
    return file?.link || null;
  } catch (e) { return null; }
}
async function pixabay(query) {
  if (!PIXABAY_KEY) return null;
  try {
    const r = await fetch(`https://pixabay.com/api/videos/?key=${PIXABAY_KEY}&q=${encodeURIComponent(query)}&per_page=3`);
    if (!r.ok) return null;
    const d = await r.json();
    const v = d.hits?.[0];
    return v?.videos?.medium?.url || v?.videos?.small?.url || null;
  } catch (e) { return null; }
}

for (const scene of config.scenes) {
  if (!scene.backgroundVideo?.query || scene.backgroundVideo.url) continue;
  const q = scene.backgroundVideo.query;
  const src = scene.backgroundVideo.source || 'pexels';
  let url = null;
  if (src === 'pexels' || !url) url = await pexels(q);
  if (!url) url = await pixabay(q);
  if (url) {
    scene.backgroundVideo.url = url;
    scene.backgroundVideo.source = url.includes('pexels') ? 'pexels' : 'pixabay';
  }
}
return [{ json: { ...item, config } }];
